import org.eclipse.jetty.server.Server
import org.eclipse.jetty.server.handler.AbstractHandler
import org.eclipse.jetty.server.Request
import org.eclipse.jetty.http.HttpStatus
import java.io.PrintWriter

object SQLQueryExecutor extends App {
  val spark: SparkSession = SparkSession.builder()
    .appName("SQLQueryExecutor")
    .getOrCreate()

  // Handler for incoming API requests
  class QueryHandler extends AbstractHandler {
    override def handle(target: String, baseRequest: Request, request: javax.servlet.http.HttpServletRequest, response: javax.servlet.http.HttpServletResponse): Unit = {
      if (target.equals("/executeQuery")) {
        val userQuery = request.getParameter("query")
        
