          val result: DataFrame = spark.sql(userQuery)
          val output = result.collect().mkString("\n")

          response.setContentType("text/plain;charset=utf-8")
          response.setStatus(HttpStatus.OK_200)
          val out = new PrintWriter(response.getOutputStream)
          out.println(output)
          out.flush()
          baseRequest.setHandled(true)
        } catch {
          case e: Exception =>
            response.setStatus(HttpStatus.BAD_REQUEST_400)
            response.getWriter.println(s"Error executing query: ${e.getMessage}")
            baseRequest.setHandled(true)
        }
      }
    }
  }

  // Start Jetty Server
  val server = new Server(8080)
  server.setHandler(new QueryHandler)
  server.start()
  server.join()
}